# The BFS approach doesn't work well for spirals.
# Let me try a ray-casting approach: for each cell, count how many fg "walls" 
# a ray to the right crosses. Each continuous fg segment = 1 wall.

def compute_winding(grid, bg, fg):
    H, W = grid.shape
    depth = np.zeros((H, W), dtype=int)

    for r in range(H):
        for c in range(W):
            if grid[r, c] == fg:
                depth[r, c] = -1  # will handle separately
                continue
            # Cast ray upward and count fg segments
            crossings = 0
            in_fg = False
            for rr in range(r-1, -1, -1):
                if grid[rr, c] == fg:
                    if not in_fg:
                        crossings += 1
                        in_fg = True
                else:
                    in_fg = False
            depth[r, c] = crossings

    return depth

for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    bg = [3, 1, 4, 2][i]
    fg = [4, 4, 9, 4][i]

    depth = compute_winding(inp, bg, fg)
    print(f"Example {i}: unique depths (bg cells) = {sorted(int(x) for x in np.unique(depth[depth >= 0]))}")

    # Show the depth map for non-fg cells
    for r in range(min(inp.shape[0], 20)):
        row_str = ""
        for c in range(inp.shape[1]):
            if depth[r, c] == -1:
                row_str += "# "
            else:
                row_str += f"{int(depth[r,c])} "
        print(f"  {row_str.strip()}")
    print()

