# Build proper containment tree using BFS from outer bg regions
from collections import deque

def build_containment_tree(grid, bg, fg):
    H, W = grid.shape
    bg_labeled, bg_num = ndimage.label(grid == bg)
    fg_labeled, fg_num = ndimage.label(grid == fg)

    # Identify outer bg labels (touching padded boundary)
    padded = np.full((H+2, W+2), bg, dtype=int)
    padded[1:-1, 1:-1] = grid
    bg_labeled_p, _ = ndimage.label(padded == bg)
    outer_bg_p_label = bg_labeled_p[0, 0]

    outer_bg_labels = set()
    for r in range(H):
        for c in range(W):
            if grid[r,c] == bg and bg_labeled_p[r+1, c+1] == outer_bg_p_label:
                outer_bg_labels.add(int(bg_labeled[r,c]))

    # Build adjacency between bg and fg regions
    bg_to_fg = {i: set() for i in range(1, bg_num+1)}
    fg_to_bg = {i: set() for i in range(1, fg_num+1)}

    for r in range(H):
        for c in range(W):
            if grid[r,c] == bg:
                bl = int(bg_labeled[r,c])
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] == fg:
                        fl = int(fg_labeled[nr,nc])
                        bg_to_fg[bl].add(fl)
                        fg_to_bg[fl].add(bl)

    # Assign depths using BFS
    # Nodes: ('bg', i) or ('fg', i)
    # Outer bg has depth 0
    # Adjacent nodes alternate between bg and fg

    depth = {}
    parent = {}
    children = {}

    q = deque()
    for bl in outer_bg_labels:
        depth[('bg', bl)] = 0
        parent[('bg', bl)] = None
        children[('bg', bl)] = []
        q.append(('bg', bl))

    while q:
        node = q.popleft()
        d = depth[node]

        if node[0] == 'bg':
            bl = node[1]
            for fl in bg_to_fg[bl]:
                fn = ('fg', fl)
                if fn not in depth:
                    depth[fn] = d + 1
                    parent[fn] = node
                    children[fn] = []
                    children[node].append(fn)
                    q.append(fn)
        else:  # fg
            fl = node[1]
            for bl in fg_to_bg[fl]:
                bn = ('bg', bl)
                if bn not in depth:
                    depth[bn] = d + 1
                    parent[bn] = node
                    children[bn] = []
                    children[node].append(bn)
                    q.append(bn)

    return depth, parent, children, bg_labeled, fg_labeled, outer_bg_labels

for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    bg = [3, 1, 4, 2][i]
    fg = [4, 4, 9, 4][i]

    depth, parent, children, bg_lab, fg_lab, outer_bg = build_containment_tree(inp, bg, fg)

    print(f"Example {i}:")
    for node in sorted(depth.keys()):
        d = depth[node]
        p = parent[node]
        ch = children[node]
        print(f"  {node}: depth={d}, parent={p}, children={ch}")
    print()

