# Let me fix the clustering logic
# The issue: row_range=0 causes items to be split, and 2-item cases need the range comparison

def solve(grid):
    import numpy as np
    from scipy import ndimage
    from collections import deque

    grid = np.array(grid)
    H, W = grid.shape

    colors, counts = np.unique(grid, return_counts=True)
    bg = int(colors[np.argmax(counts)])
    fg = int(colors[np.argmin(counts)])

    bg_labeled, bg_num = ndimage.label(grid == bg)
    fg_labeled, fg_num = ndimage.label(grid == fg)

    padded_g = np.full((H+2, W+2), bg, dtype=int)
    padded_g[1:-1, 1:-1] = grid
    bg_labeled_p, _ = ndimage.label(padded_g == bg)
    outer_bg_p = bg_labeled_p[0, 0]

    outer_bg_labels = set()
    for r in range(H):
        for c in range(W):
            if grid[r,c] == bg and bg_labeled_p[r+1, c+1] == outer_bg_p:
                outer_bg_labels.add(int(bg_labeled[r,c]))

    bg_to_fg = {i: set() for i in range(1, bg_num+1)}
    fg_to_bg = {i: set() for i in range(1, fg_num+1)}

    for r in range(H):
        for c in range(W):
            if grid[r,c] == bg:
                bl = int(bg_labeled[r,c])
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if 0 <= nr < H and 0 <= nc < W and grid[nr,nc] == fg:
                        fl = int(fg_labeled[nr,nc])
                        bg_to_fg[bl].add(fl)
                        fg_to_bg[fl].add(bl)

    depth = {}
    parent = {}
    children = {}

    q = deque()
    for bl in outer_bg_labels:
        node = ('bg', bl)
        depth[node] = 0
        parent[node] = None
        children[node] = []
        q.append(node)

    while q:
        node = q.popleft()
        d = depth[node]
        if node[0] == 'bg':
            for fl in bg_to_fg[node[1]]:
                fn = ('fg', fl)
                if fn not in depth:
                    depth[fn] = d + 1
                    parent[fn] = node
                    children[fn] = []
                    children[node].append(fn)
                    q.append(fn)
        else:
            for bl in fg_to_bg[node[1]]:
                bn = ('bg', bl)
                if bn not in depth:
                    depth[bn] = d + 1
                    parent[bn] = node
                    children[bn] = []
                    children[node].append(bn)
                    q.append(bn)

    fg_centers = {}
    for fi in range(1, fg_num+1):
        rows, cols = np.where(fg_labeled == fi)
        fg_centers[fi] = (float(rows.mean()), float(cols.mean()))

    def render_horizontal_group(items):
        """items: list of (render, cr, cc). Returns (render, cr, cc)"""
        if len(items) == 1:
            return items[0]

        renders = [d[0] for d in items]
        crs = [d[1] for d in items]
        ccs = [d[2] for d in items]
        heights = [len(r) for r in renders]
        widths = [len(r[0]) for r in renders]

        max_above = max(crs)
        max_below = max(h - cr - 1 for h, cr in zip(heights, crs))

        total_h = max_above + 1 + max_below
        total_w = sum(widths) + (len(widths) - 1)

        result = [[bg]*total_w for _ in range(total_h)]

        col_offset = 0
        center_row = max_above
        main_cc = None
        max_d = -1

        for idx in range(len(items)):
            ch_h, ch_w = heights[idx], widths[idx]
            row_start = center_row - crs[idx]

            for r in range(ch_h):
                for c in range(ch_w):
                    result[row_start + r][col_offset + c] = renders[idx][r][c]

            if crs[idx] > max_d:
                max_d = crs[idx]
                main_cc = col_offset + ccs[idx]

            col_offset += ch_w + 1

        return result, center_row, main_cc

    def render_vertical_group(items):
        """items: list of (render, cr, cc). Returns (render, cr, cc)"""
        if len(items) == 1:
            return items[0]

        renders = [d[0] for d in items]
        crs = [d[1] for d in items]
        ccs = [d[2] for d in items]
        heights = [len(r) for r in renders]
        widths = [len(r[0]) for r in renders]

        max_left = max(ccs)
        max_right = max(w - cc - 1 for w, cc in zip(widths, ccs))

        total_w = max_left + 1 + max_right
        total_h = sum(heights) + (len(heights) - 1)

        result = [[bg]*total_w for _ in range(total_h)]

        row_offset = 0
        center_col = max_left
        main_cr = None
        max_d = -1

        for idx in range(len(items)):
            ch_h, ch_w = heights[idx], widths[idx]
            col_start = center_col - ccs[idx]

            for r in range(ch_h):
                for c in range(ch_w):
                    result[row_offset + r][col_start + c] = renders[idx][r][c]

            if crs[idx] > max_d:
                max_d = crs[idx]
                main_cr = row_offset + crs[idx]

            row_offset += ch_h + 1

        return result, main_cr, center_col

    def arrange_children(child_rendered):
        """child_rendered: list of (node, render, cr, cc, orig_center)
        Returns (render, cr, cc) for the combined arrangement"""

        if len(child_rendered) == 1:
            return child_rendered[0][1], child_rendered[0][2], child_rendered[0][3]

        centers_r = [d[4][0] for d in child_rendered]
        centers_c = [d[4][1] for d in child_rendered]
        r_range = max(centers_r) - min(centers_r)
        c_range = max(centers_c) - min(centers_c)

        if len(child_rendered) == 2:
            # Simple H or V arrangement
            if c_range >= r_range:
                sorted_items = sorted(child_rendered, key=lambda d: d[4][1])
                items = [(d[1], d[2], d[3]) for d in sorted_items]
                return render_horizontal_group(items)
            else:
                sorted_items = sorted(child_rendered, key=lambda d: d[4][0])
                items = [(d[1], d[2], d[3]) for d in sorted_items]
                return render_vertical_group(items)

        # 3+ children: 2D layout using row clustering
        sorted_by_row = sorted(child_rendered, key=lambda d: d[4][0])

        # Cluster into row groups
        if r_range <= 0.01:
            # All at same row → single horizontal group
            groups = [sorted_by_row]
        else:
            groups = [[sorted_by_row[0]]]
            for item in sorted_by_row[1:]:
                prev_row = groups[-1][-1][4][0]
                curr_row = item[4][0]
                if (curr_row - prev_row) / r_range < 0.3:
                    groups[-1].append(item)
                else:
                    groups.append([item])

        # Sort each group by column
        for group in groups:
            group.sort(key=lambda d: d[4][1])

        # Render each group horizontally
        group_renders = []
        for group in groups:
            items = [(d[1], d[2], d[3]) for d in group]
            g_r, g_cr, g_cc = render_horizontal_group(items)
            group_renders.append((g_r, g_cr, g_cc))

        if len(group_renders) == 1:
            return group_renders[0]
        else:
            return render_vertical_group(group_renders)

    def get_center_and_size(node):
        if node[0] == 'fg':
            ch = children[node]
            if not ch:
                return ([[fg]], 0, 0)
            else:
                bg_child = ch[0]
                bg_render, bg_cr, bg_cc = get_center_and_size(bg_child)
                bh, bw = len(bg_render), len(bg_render[0])
                result = [[fg]*(bw+2)]
                for row in bg_render:
                    result.append([fg] + row + [fg])
                result.append([fg]*(bw+2))
                return (result, 1 + bg_cr, 1 + bg_cc)

        else:  # bg
            ch = children[node]
            if not ch:
                return ([[bg]], 0, 0)

            child_rendered = []
            for child in ch:
                c_render, c_cr, c_cc = get_center_and_size(child)
                fi = child[1]
                orig_center = fg_centers[fi]
                child_rendered.append((child, c_render, c_cr, c_cc, orig_center))

            inner_render, inner_cr, inner_cc = arrange_children(child_rendered)

            # Add bg padding
            ih, iw = len(inner_render), len(inner_render[0])
            result = [[bg]*(iw+2)]
            for row in inner_render:
                result.append([bg] + row + [bg])
            result.append([bg]*(iw+2))
            return (result, 1 + inner_cr, 1 + inner_cc)

    # Find depth-1 fg nodes
    depth1_fgs = [n for n in depth if n[0] == 'fg' and depth[n] == 1]

    if len(depth1_fgs) == 1:
        result, _, _ = get_center_and_size(depth1_fgs[0])
        return [row[:] for row in result]

    # Multiple depth-1 fg nodes - outer level
    fg_data = []
    for node in depth1_fgs:
        render, cr, cc = get_center_and_size(node)
        orig_center = fg_centers[node[1]]
        fg_data.append((node, render, cr, cc, orig_center))

    inner_render, inner_cr, inner_cc = arrange_children(fg_data)

    # Add trailing padding for outer multi-tree case
    rh, rw = len(inner_render), len(inner_render[0])
    padded_result = [[bg]*(rw+1) for _ in range(rh)]
    for r in range(rh):
        for c in range(rw):
            padded_result[r][c] = inner_render[r][c]

    return [row[:] for row in padded_result]

# Test
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    result_arr = np.array(result)
    expected_arr = np.array(expected)
    match = np.array_equal(result_arr, expected_arr)
    print(f"Example {i}: {'MATCH' if match else 'MISMATCH'} ({result_arr.shape} vs {expected_arr.shape})")
    if not match:
        print(f"  Expected:\n{expected_arr.tolist()}")
        print(f"  Got:\n{result_arr.tolist()}")

